      "type": "object",
      "properties": {
        "signal_type": {
          "type": "string",
          "description": "The type of alert signal (e.g., 'Unauthorized Entry')."
        },
        "corridor_name": {
          "type": "string",
          "description": "The specific area to search (e.g., 'Western Corridor')."
        }
      },
      "required": [
        "signal_type",
        "corridor_name"
      ]
    },
    "example_output": {
      "logs": [
        {
          "timestamp": "2023-10-27T14:30:00Z",
          "station_id": "SNSR-992",
          "event": "Motion detected"
        }
      ]
    }
  },
  "get_equipment_registry": {
    "description": "Retrieves the physical location and status of hardware from the equipment registry using a unique ID.",
    "parameters": {
      "type": "object",
      "properties": {
