        "lat": -3.12,
        "lon": 37.45
      },
      "type": "Automated Sensor"
    }
  },
  "get_drone_status": {
    "description": "Checks the current location, battery level, and health of a specific drone.",
    "parameters": {
      "type": "object",
      "properties": {
        "drone_id": {
          "type": "string",
          "description": "The ID of the drone (e.g., 'D-01')."
        }
      },
      "required": [
        "drone_id"
      ]
    },
    "example_output": {
      "battery_level": 82,
      "current_coords": [
        -3.05,
        37.35
      ],
