          "type": "string",
          "description": "The drone to use for the scan."
        },
        "target_id": {
          "type": "string",
          "description": "The ID of the animal/object to identify (e.g., 'R-102')."
        },
        "visibility_range_km": {
          "type": "number",
          "description": "The maximum distance at which the camera can identify the target."
        }
      },
      "required": [
        "drone_id",
        "target_id",
        "visibility_range_km"
      ]
    },
    "example_output": {
